#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

int longestIncreasingSubsequenceLength(int n, const vector<int>& nums) {
    vector<int> lis(n, 1); // Initialize LIS values for all indexes as 1

    // Compute optimized LIS values in bottom up manner
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (nums[i] > nums[j] && lis[i] < lis[j] + 1) {
                lis[i] = lis[j] + 1;
            }
        }
    }

    // Pick maximum of all LIS values
    return *max_element(lis.begin(), lis.end());
}

int main() {
    int n;
    cout << "Enter the number of elements in the sequence: ";
    cin >> n;

    vector<int> nums(n);
    cout << "Enter the sequence of integers: ";
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }

    int result = longestIncreasingSubsequenceLength(n, nums);
    cout << "Length of the longest increasing subsequence: " << result << endl;

    return 0;
}
```

