```cpp
#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

int longestIncreasingSubsequenceLength(const vector<int>& nums) {
    int n = nums.size();
    if (n == 0) return 0;

    // Initialize the dp array where dp[i] represents the length of the longest increasing subsequence
    // ending with nums[i]
    vector<int> dp(n, 1);

    // Build the dp array from the end to the beginning
    for (int i = 1; i < n; ++i) {
        for (int j = 0; j < i; ++j) {
            if (nums[j] < nums[i]) {
                dp[i] = max(dp[i], dp[j] + 1);
            }
        }
    }

    // The length of the longest increasing subsequence is the maximum value in dp array
    return *max_element(dp.begin(), dp.end());
}

int main() {
    int n;
    cout << "Enter the length of the sequence: ";
    cin >> n;

    vector<int> nums(n);
    cout << "Enter " << n << " integers: ";
    for (int i = 0; i < n; ++i) {
        cin >> nums[i];
    }

    int lisLength = longestIncreasingSubsequenceLength(nums);
    cout << "The length of the longest increasing subsequence is: " << lisLength << endl;

    return 0;
}
```

