```cpp
#include <iostream>
#include <vector>
#include <algorithm>

int findLISLength(const std::vector<int>& nums) {
    if (nums.empty()) return 0;

    std::vector<int> dp(nums.size(), 1); // dp[i] will be the length of the longest increasing subsequence ending with nums[i]

    for (size_t i = 1; i < nums.size(); ++i) {
        for (size_t j = 0; j < i; ++j) {
            if (nums[i] > nums[j])
                dp[i] = std::max(dp[i], dp[j] + 1);
        }
    }

    return *std::max_element(dp.begin(), dp.end());
}

int main() {
    int n;
    std::cout << "Enter the number of elements in the sequence: ";
    std::cin >> n;

    std::vector<int> sequence(n);
    std::cout << "Enter the sequence of integers: ";
    for (int i = 0; i < n; ++i) {
        std::cin >> sequence[i];
    }

    int lisLength = findLISLength(sequence);
    std::cout << "The length of the longest increasing subsequence is: " << lisLength << std::endl;

    return 0;
}
```

